//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: **Numbering changes under tracked changes (numberingChange, ins numPr)**.
//!
//! Each `#[test]` encodes a declarative TestSpec mined from ECMA-376 / ISO 29500 /
//! MS-OI29500. A **FAIL here is a real Word-compliance gap** in the stemma engine,
//! not a test to be weakened: the assertion text carries the rule + the §refs so a
//! failure is self-explanatory. Do not relax an assertion to make it green — trace
//! the divergence to its source per CLAUDE.md ("Fix at the source").
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. `reserialize()` of an unedited document therefore reflects
//! stemma's verbatim-preservation contract, not Word's render normalization. The
//! `xml*` assertions below only target child/element ORDERING (Annex A schema
//! sequence) and structural validity — markup the serializer actively restructures
//! or must preserve in order — never "Word ignores value V on layout". Consumption
//! semantics are asserted on the READ side (`read_accepted`/`read_rejected`).

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal-docx plumbing ─────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>`. `extra_parts` are
/// `(part_name, xml)` pairs (e.g. `("word/numbering.xml", "<w:numbering…/>")`);
/// each gets a `[Content_Types].xml` Override based on its part name and a
/// relationship from `word/document.xml`.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type override per known part. Fail loud on an unknown extra part
    // rather than guessing a content type (no silent fallback).
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    let mut doc_rel_entries = String::new();
    for (i, (part, _xml)) in extra_parts.iter().enumerate() {
        let (ct, rel_type) = match *part {
            "word/numbering.xml" => (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
            ),
            "word/styles.xml" => (
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml",
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
            ),
            other => panic!("make_docx: unknown extra part {other}; add its content type"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{part}" ContentType="{ct}"/>"#
        ));
        // Target is relative to word/ (the document.xml.rels base).
        let target = part.strip_prefix("word/").unwrap_or(part);
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let reader = std::io::Cursor::new(docx);
    let mut zip = zip::ZipArchive::new(reader).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    use std::io::Read;
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml utf8");
    s
}

/// Parse `bytes`, re-serialize through the engine's default export path, and
/// return the resulting `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse docx");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize docx");
    document_xml_of(&out)
}

/// Collapse inter-tag whitespace so an ordering assertion that allows `\s*`
/// between two elements becomes a plain substring check. Whitespace that sits
/// strictly between a `>` and a `<` is removed; everything else is left intact.
fn collapse_intertag_ws(xml: &str) -> String {
    let bytes = xml.as_bytes();
    let mut out = String::with_capacity(xml.len());
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i] as char;
        if c == '>' {
            out.push('>');
            i += 1;
            // Skip a whitespace run, but only when it is followed by a '<'.
            let mut j = i;
            while j < bytes.len() && (bytes[j] as char).is_whitespace() {
                j += 1;
            }
            if j < bytes.len() && bytes[j] == b'<' {
                i = j; // drop the whitespace run between tags
            }
            continue;
        }
        out.push(c);
        i += 1;
    }
    out
}

/// Assert the document opens clean: `validate(bytes)` reports no errors.
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{msg}\n  validate() reported issues: {:?}",
        report.issues
    );
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

