#[test]
fn numbering_change_on_listnum_fldchar_opens_clean() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"><w:numberingChange w:id="0" w:author="A" w:date="2006-01-01T10:00:00Z" w:original="1."/></w:fldChar></w:r><w:r><w:instrText>LISTNUM</w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>2.</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r><w:r><w:t>body</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "numberingChange nested in a fldChar begin is the standard's own LISTNUM revision shape (Part 4 §14.7.1.1) and a member of CT_FldChar's choice; Word opens it without repair (Annex A CT_FldChar)",
    );
    assert_eq!(
        accept_text(&b),
        "2.body",
        "numberingChange is only a numbering cache and carries no run text; accepting leaves the field result run (2.) and trailing body run intact (Part 4 §14.7.1.1)"
    );
    assert_eq!(
        reject_text(&b),
        "2.body",
        "Rejecting a numberingChange (a history cache, not pending content) does not remove any run text; visible paragraph text is unchanged (Part 4 §14.7.1.1)"
    );
}

